def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        multiplier = 1.0
        score = 0.0
        penalty = 0.0
        bonus = 0.0
        for j in range(1, 15):
            if j % 3 == 0 and ratio < 0.5:
                multiplier *= (1 + 0.05 * j)
                score += np.sin(ratio * j) * np.log1p(j)
            elif j % 5 == 0 and ratio > 0.7:
                multiplier *= (0.85 - 0.01 * j)
                penalty += np.cos(ratio * j) * (j ** 0.7)
            else:
                score += (j ** 1.3) / (1 + ratio * j) * np.exp(-0.1 * ratio * j)
            if cap % (j+2) == 0:
                bonus += np.sqrt(j) * np.tanh(score / (j+2))
            else:
                bonus -= np.arctan(penalty / (j+2))
            if j % 4 == 0:
                penalty += 0.03 * j * np.sin(cap/(j+1))
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k+1) == 0:
                    bonus += np.log1p(residual) / (k + 0.7)
                else:
                    penalty += (residual ** 0.33) / (k + 1.2)
            else:
                penalty += abs(residual)**1.2 * 0.15 * k
        if ratio > 1.1:
            priority_raw = - (score * multiplier + bonus - penalty) * np.exp(-ratio*0.8)
        elif ratio < 0.15:
            priority_raw = - (score * multiplier + bonus * 0.5 - penalty * 1.5) / (cap + 1.1)
        else:
            priority_raw = - ((score * multiplier + bonus) / (cap ** 0.7 + 2) - penalty * 0.8)
        if item > cap * 0.6 and item < cap:
            priority_raw *= 1.1 + 0.2 * np.sin(item * cap / (j+1))
        if penalty > 5:
            priority_raw *= 1.3
        if bonus < -3:
            priority_raw *= 0.7
        priorities[i] = priority_raw
    return priorities
